import json

# Check what data we have available
print('Available storage keys:')
for key in list(locals().keys()):
    if key.startswith('var_'):
        print(key)

# Load NYSE symbols from query_db:20
nyse_file = locals()['var_functions.query_db:20']
if isinstance(nyse_file, str):
    with open(nyse_file, 'r') as f:
        nyse_data = json.load(f)
else:
    nyse_data = nyse_file

print('\nNYSE stocks found: ' + str(len(nyse_data)))
nyse_symbols = [stock['Symbol'] for stock in nyse_data]
company_names = {stock['Symbol']: stock['Company Description'] for stock in nyse_data}

# Load all tables from list_db:28
tables_file = locals()['var_functions.list_db:28']
if isinstance(tables_file, str):
    with open(tables_file, 'r') as f:
        all_tables = json.load(f)
else:
    all_tables = tables_file

# Find intersection
available_symbols = []
for sym in nyse_symbols:
    if sym in all_tables:
        available_symbols.append(sym)

print('Symbols with trading data: ' + str(len(available_symbols)))
print('First 10: ' + str(available_symbols[:10]))

result = {
    'available_symbols': available_symbols,
    'company_names': company_names
}

print('__RESULT__:')
print(json.dumps(result, ensure_ascii=False))

